const orderNumber = query.split(",")[0]?.trim();
const reason = query.split(",")[1]?.trim() || "change_of_mind";
const itemName = query.split(",")[2]?.trim() || "item";

const returnId = "RTN-" + Math.floor(Math.random() * 90000 + 10000);

const freeShipping = reason.toLowerCase().includes("defect");

return JSON.stringify({
  returnId: returnId,
  orderNumber: orderNumber,
  item: itemName,
  reason: reason,
  status: "Return initiated",
  instructions: "A prepaid return label will be emailed within 2 hours. Please pack the item in its original packaging and drop it at any SingPost outlet. Refund will be processed within 5-7 business days of receiving the item.",
  freeShipping: freeShipping
});

const catalogue = {
  "alpine pro backpack 45l": {
    name: "Alpine Pro Backpack 45L",
    price: 289,
    colours: ["Forest Green", "Storm Grey", "Desert Sand"],
    features: "Waterproof ripstop nylon, adjustable torso length, integrated rain cover, hydration sleeve, 9 pockets including hip belt storage. Weight: 1.4kg.",
    sizing: "One size fits torso lengths 40-52cm. Adjustable shoulder straps and hip belt.",
    care: "Spot clean with mild soap. Do not machine wash. Hang dry. Reapply DWR coating annually.",
    bestFor: "Multi-day hiking and backpacking trips"
  },
  "ridgeline waterproof jacket": {
    name: "Ridgeline Waterproof Jacket",
    price: 349,
    colours: ["Storm Blue", "Alpine Red", "Black"],
    sizes: ["XS", "S", "M", "L", "XL", "XXL"],
    features: "3-layer Gore-Tex membrane, fully taped seams, helmet-compatible hood, pit zips, 3 external pockets. Weight: 380g.",
    sizing: "Slim athletic fit. Size up if layering over fleece. See size chart on product page.",
    care: "Machine wash cold on gentle cycle. Tumble dry low to reactivate DWR. Do not iron or dry clean.",
    bestFor: "Mountain hiking and trail running in wet conditions"
  },
  "summit trekking poles": {
    name: "Summit Trekking Poles",
    price: 129,
    colours: ["Carbon Black", "Silver"],
    features: "Carbon fibre shaft, 3-section telescoping (65-135cm), quick-lock mechanism, cork grips with extended foam, tungsten carbide tips. Weight: 195g per pole.",
    care: "Wipe down after use. Dry fully before storing collapsed. Lubricate lock mechanism seasonally.",
    bestFor: "Day hikes to multi-day treks on varied terrain"
  },
  "basecamp 2-person tent": {
    name: "Basecamp 2-Person Tent",
    price: 459,
    colours: ["Sage", "Burnt Orange"],
    features: "Freestanding dome, 3-season, 2 vestibules, 2 doors, DAC Featherlite poles, 3000mm waterproof floor, 8.5 sqm interior. Weight: 2.1kg packed.",
    sizing: "Sleeps 2 comfortably. Interior: 220cm x 130cm x 105cm height.",
    care: "Dry completely before storing. Never store compressed when wet. Seam seal annually.",
    bestFor: "Backcountry camping in spring, summer, and autumn"
  },
  "thermosleep sleeping bag -5c": {
    name: "ThermoSleep Sleeping Bag -5C",
    price: 219,
    colours: ["Midnight", "Olive"],
    features: "Synthetic insulation rated to -5C comfort, mummy shape, draft collar, full-length zip baffle, compression sack included. Weight: 1.3kg.",
    sizing: "Regular fits up to 183cm. Long version available for up to 198cm.",
    care: "Machine wash front-loader only, gentle cycle. Tumble dry low with tennis balls to restore loft. Store uncompressed.",
    bestFor: "3-season camping and cooler shoulder season trips"
  }
};

const searchTerm = query.toLowerCase();
let results = [];

for (const [key, product] of Object.entries(catalogue)) {
  if (searchTerm.includes(key) || key.includes(searchTerm) ||
      product.bestFor.toLowerCase().includes(searchTerm) ||
      product.features.toLowerCase().includes(searchTerm)) {
    results.push(product);
  }
}

if (results.length === 0) {
  const allProducts = Object.values(catalogue).map(p =>
    `${p.name} ($${p.price}) - ${p.bestFor}`
  ).join("\n");
  return "No exact match found. Here is our full product range:\n" + allProducts;
}

return results.map(p =>
  `${p.name} - $${p.price}\nColours: ${p.colours.join(", ")}\nFeatures: ${p.features}\n${p.sizing ? "Sizing: " + p.sizing + "\n" : ""}Care: ${p.care}\nBest for: ${p.bestFor}`
).join("\n\n");

const reason = query.split("|")[0]?.trim() || "Customer requested human agent";
const summary = query.split("|")[1]?.trim() || "No summary available";

const ticketId = "ESC-" + Math.floor(Math.random() * 90000 + 10000);
const timestamp = new Date().toLocaleString("en-SG", { timeZone: "Asia/Singapore" });

const escalationRecord = {
  ticketId: ticketId,
  timestamp: timestamp,
  reason: reason,
  conversationSummary: summary,
  priority: reason.toLowerCase().includes("angry") || reason.toLowerCase().includes("frustrat") ? "HIGH" : "NORMAL",
  status: "Queued for human agent",
  estimatedWaitTime: "Under 5 minutes",
  channel: "Live Chat",
  message: "I've created escalation ticket " + ticketId + ". A member of our team will be with you shortly. I've shared a full summary of our conversation so you won't need to repeat anything."
};

return JSON.stringify(escalationRecord);

const situation = query.toLowerCase();

let response = "";

if (situation.includes("warranty") || situation.includes("defect") || situation.includes("broken")) {
  response = "RETURNS SPECIALIST ASSESSMENT:

";
  response += "This appears to be a WARRANTY/DEFECT claim.

";
  response += "Policy: All Horizon Outdoors products carry a 12-month warranty from date of purchase covering manufacturing defects (not wear and tear).

";
  response += "Requirements:
- Order number for purchase verification
- Photos of the defect
- Description of when the issue was first noticed

";
  response += "If approved, customer can choose: full replacement OR full refund.
";
  response += "Free return shipping applies for all warranty claims.
";
  response += "Processing time: 5-7 business days after item received.";
} else if (situation.includes("gift")) {
  response = "RETURNS SPECIALIST ASSESSMENT:

";
  response += "This is a GIFT RETURN.

";
  response += "Policy: Gift purchases can be returned with a gift receipt for STORE CREDIT only (no cash refund).

";
  response += "Requirements:
- Gift receipt OR order number from the purchaser
- Item must be unused and in original packaging
- 30-day return window from delivery date

";
  response += "Customer pays return shipping ($12.90 flat rate) unless item is defective.
";
  response += "Store credit issued within 3 business days of receiving the item.";
} else if (situation.includes("exchange") || situation.includes("size") || situation.includes("colour") || situation.includes("color") || situation.includes("swap")) {
  response = "RETURNS SPECIALIST ASSESSMENT:

";
  response += "This is an EXCHANGE request.

";
  response += "Policy: Exchanges processed for different size or colour of the SAME item at no charge.

";
  response += "Process:
1. Confirm which item and desired new size/colour
2. Verify new size/colour is in stock
3. Generate prepaid return label (free for exchanges)
4. Ship replacement once original item is scanned at SingPost

";
  response += "Estimated timeline: 3-5 business days after drop-off.";
} else if (situation.includes("refund") || situation.includes("money back")) {
  response = "RETURNS SPECIALIST ASSESSMENT:

";
  response += "This is a REFUND request.

";
  response += "Policy:
- 30-day window from delivery date
- Item must be unused and in original packaging
- Defective items: free return shipping + full refund
- Change of mind: customer pays return shipping ($12.90 flat rate) + full refund

";
  response += "Refund method: Original payment method
";
  response += "Processing time: 5-7 business days after item received.
";
  response += "Note: Sale items are final sale and cannot be refunded, only exchanged.";
} else {
  response = "RETURNS SPECIALIST ASSESSMENT:

";
  response += "General returns guidance:

";
  response += "- 30-day return window from delivery date
";
  response += "- Items must be unused and in original packaging
";
  response += "- Defective: free return shipping
";
  response += "- Change of mind: $12.90 flat rate return shipping
";
  response += "- Exchanges (size/colour): free, same item only
";
  response += "- Gift returns: store credit with gift receipt
";
  response += "- Warranty: 12 months, manufacturing defects only
";
  response += "- Refunds processed in 5-7 business days

";
  response += "Please provide more details about the customer's specific situation for a tailored recommendation.";
}

return response;
